{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/WrappingRuleRawStringTest.kt","content":"package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MULTILINE_STRING_QUOTE
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

internal class WrappingRuleRawStringTest {
    private val wrappingRuleAssertThat = assertThatRule { WrappingRule() }

    @Test
    fun `Given a raw string with a let block exceeding the max line length then do not require wrapping inside the string template`() {
        val code =
            """
            package test

            class QueryGenerator {
                fun getQueryString(query: QueryRequest): String {
                    val q = $MULTILINE_STRING_QUOTE
                        SELECT *
                        FROM table_name_long_enough_so_max_line_length_is_met_and_wrapping_rule_is_violated_and_generates_an_error WHERE 1 = 1 $.{query.gameId?.let { "AND id = ?" } ?: ""}
                    $MULTILINE_STRING_QUOTE
                    return q
                }
            }

            data class QueryRequest(
                val gameId: String?,
            )
            """.trimIndent()
                .replacePlaceholderWithStringTemplate()
        wrappingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to "120")
            .hasNoLintViolations()
    }

    private fun String.replacePlaceholderWithStringTemplate() = replace("$.", "${'$'}")
}
"}

